    <script>
        function updateStickyLayout() {
        const card = document.querySelector('.card');
        const sales = document.querySelector('.sales-sec');
        const sku = document.querySelector('.sku-box');

        if (!card || !sales || !sku) return;

        const gap = 30;

        if (window.innerWidth > 1024) {
            const cardTop = 120;
            card.style.top = `${cardTop}px`;
            card.style.position = 'sticky';

            const cardHeight = card.offsetHeight;
            const salesHeight = sales.offsetHeight;
            const skuHeight = sku.offsetHeight;

            const salesTop = cardTop + cardHeight + gap;
            const skuTop = salesTop + salesHeight + gap;

            sales.style.top = `${salesTop}px`;
            sku.style.top = `${skuTop}px`;
            
            card.style.marginBottom = `${gap + salesHeight + gap + skuHeight}px`;
            sales.style.marginBottom = `${gap + skuHeight}px`;
            sku.style.marginBottom = `0px`;
        }

        [card, sales, sku].forEach(el => {
            el.classList.add('show');
        });
        }

        window.addEventListener('load', updateStickyLayout);
        window.addEventListener('resize', updateStickyLayout);
    </script>
